"use strict";(self.webpackChunk_servicenow_sdk_docs=self.webpackChunk_servicenow_sdk_docs||[]).push([["351886"],{248152(e){e.exports=JSON.parse('{"tag":{"label":"knowledge base","permalink":"/sdk/tags/knowledge-base","allTagsPath":"/sdk/tags","count":2,"items":[{"id":"guides/knowledge-base-access-guide","title":"Knowledge Base Access Controls Guide","description":"This guide explains how to configure who can read and who can contribute to a ServiceNow Knowledge Base using Fluent. It covers the four M2M tables that link knowledge bases to user criteria, with examples for granting, denying, and replacing access entries.","permalink":"/sdk/guides/knowledge-base-access-guide"},{"id":"guides/user-criteria-guide","title":"User Criteria","description":"User Criteria (user_criteria) are named, reusable access conditions that determine which users can view catalog items, knowledge articles, service portal topics, and other platform content. Required for controlling Service Catalog item visibility\u2014always use instead of ACLs or the roles property for who can see/order catalog items. Unlike ACLs\u2014which control read/write/delete operations on database records\u2014User Criteria define audience membership based on combinations of users, groups, roles, departments, locations, companies, and optional scripts.","permalink":"/sdk/guides/user-criteria-guide"}],"unlisted":false}}')}}]);